    self,
    conversation_id: str,
    max_messages: Optional[int] = None
) -> List[Dict]:
    """获取对话历史"""
    conv = self.get_conversation(conversation_id)
    if not conv:
        return []

    if max_messages:
        return conv.get_context_window(max_messages)
    else:
        return conv.get_messages()

